import { useState } from 'react'
import { AlertCircle } from 'lucide-react'
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Alert, AlertTitle, AlertDescription } from '@/components/ui/alert'
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog'
import useKnowledgeStore from '@/stores/useKnowledgeStore'
import { useToast } from '@/hooks/use-toast'

export default function AdminKnowledgeBase() {
  const {
    faqs,
    addFaq,
    updateFaq,
    deleteFaq,
    entries,
    addEntry,
    updateEntry,
    deleteEntry,
    systemContext,
    setSystemContext,
  } = useKnowledgeStore()

  const { toast } = useToast()

  const [editingFaqId, setEditingFaqId] = useState<string | null>(null)
  const [faqQ, setFaqQ] = useState('')
  const [faqA, setFaqA] = useState('')

  const [editingEntryId, setEditingEntryId] = useState<string | null>(null)
  const [entryT, setEntryT] = useState('')
  const [entryC, setEntryC] = useState('')

  const [deleteFaqId, setDeleteFaqId] = useState<string | null>(null)
  const [deleteEntryId, setDeleteEntryId] = useState<string | null>(null)

  const handleEditFaq = (f: any) => {
    setEditingFaqId(f.id)
    setFaqQ(f.question)
    setFaqA(f.answer)
    window.scrollTo({ top: 0, behavior: 'smooth' })
  }

  const handleSaveFaq = (e: React.FormEvent) => {
    e.preventDefault()
    if (!faqQ || !faqA) {
      toast({ title: 'Preencha todos os campos.', variant: 'destructive' })
      return
    }
    if (editingFaqId) {
      updateFaq(editingFaqId, { question: faqQ, answer: faqA })
      toast({ title: 'FAQ atualizado com sucesso!' })
    } else {
      addFaq({ question: faqQ, answer: faqA })
      toast({ title: 'Novo FAQ adicionado com sucesso!' })
    }
    setEditingFaqId(null)
    setFaqQ('')
    setFaqA('')
  }

  const confirmDeleteFaq = () => {
    if (deleteFaqId) {
      deleteFaq(deleteFaqId)
      toast({ title: 'FAQ removido com sucesso!' })
    }
    setDeleteFaqId(null)
  }

  const handleEditEntry = (e: any) => {
    setEditingEntryId(e.id)
    setEntryT(e.title)
    setEntryC(e.content)
    window.scrollTo({ top: 0, behavior: 'smooth' })
  }

  const handleSaveEntry = (e: React.FormEvent) => {
    e.preventDefault()
    if (!entryT || !entryC) {
      toast({ title: 'Preencha todos os campos.', variant: 'destructive' })
      return
    }
    if (editingEntryId) {
      updateEntry(editingEntryId, { title: entryT, content: entryC })
      toast({ title: 'Regra atualizada com sucesso!' })
    } else {
      addEntry({ title: entryT, content: entryC })
      toast({ title: 'Nova regra adicionada com sucesso!' })
    }
    setEditingEntryId(null)
    setEntryT('')
    setEntryC('')
  }

  const confirmDeleteEntry = () => {
    if (deleteEntryId) {
      deleteEntry(deleteEntryId)
      toast({ title: 'Regra removida com sucesso!' })
    }
    setDeleteEntryId(null)
  }

  const hasRefundPolicy = faqs.some(
    (f) =>
      f.question.toLowerCase().includes('reembolso') ||
      f.question.toLowerCase().includes('devolução') ||
      f.answer.toLowerCase().includes('reembolso') ||
      f.answer.toLowerCase().includes('devolução'),
  )

  const ensureRefundPolicy = () => {
    addFaq({
      question: 'Qual a política de reembolso ou devolução?',
      answer:
        'Por se tratar de um arquivo digital (não sendo enviado nenhum produto físico), não aceitamos devoluções ou reembolsos após a compra.',
    })
    toast({ title: 'Política de reembolso adicionada!' })
  }

  return (
    <div className="space-y-6 max-w-5xl animate-fade-in relative z-20">
      <h1 className="text-3xl font-bold tracking-tight">Base de Conhecimento IA</h1>

      <Card>
        <CardHeader>
          <CardTitle>Instruções e Regras Base (Sistema)</CardTitle>
        </CardHeader>
        <CardContent>
          <Textarea
            value={systemContext}
            onChange={(e) => setSystemContext(e.target.value)}
            rows={3}
            placeholder="Instruções de tom de voz para a IA..."
          />
        </CardContent>
      </Card>

      <Tabs defaultValue="faqs">
        <TabsList className="mb-4">
          <TabsTrigger value="faqs">FAQs Públicos</TabsTrigger>
          <TabsTrigger value="entries">Regras e Contexto Privado</TabsTrigger>
        </TabsList>

        <TabsContent value="faqs" className="space-y-4">
          {!hasRefundPolicy && (
            <Alert>
              <AlertCircle className="h-4 w-4" />
              <AlertTitle>Política Obrigatória Ausente</AlertTitle>
              <AlertDescription className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mt-2">
                <span>
                  A política de reembolso e devolução não foi encontrada. É recomendável mantê-la
                  para garantir respostas precisas da IA.
                </span>
                <Button variant="outline" size="sm" onClick={ensureRefundPolicy}>
                  Adicionar Política
                </Button>
              </AlertDescription>
            </Alert>
          )}

          <Card>
            <CardHeader>
              <CardTitle>{editingFaqId ? 'Editar FAQ' : 'Adicionar FAQ'}</CardTitle>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleSaveFaq} className="flex flex-col gap-4">
                <Input
                  placeholder="Pergunta"
                  value={faqQ}
                  onChange={(e) => setFaqQ(e.target.value)}
                  required
                />
                <Textarea
                  placeholder="Resposta (Suporta HTML básico)"
                  value={faqA}
                  onChange={(e) => setFaqA(e.target.value)}
                  rows={4}
                  required
                />
                <div className="flex justify-end gap-2">
                  {editingFaqId && (
                    <Button
                      type="button"
                      variant="outline"
                      onClick={() => {
                        setEditingFaqId(null)
                        setFaqQ('')
                        setFaqA('')
                      }}
                    >
                      Cancelar
                    </Button>
                  )}
                  <Button type="submit">Salvar Alterações</Button>
                </div>
              </form>
            </CardContent>
          </Card>
          <Card>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Pergunta</TableHead>
                  <TableHead className="w-40 text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {faqs.map((f) => (
                  <TableRow key={f.id}>
                    <TableCell className="font-medium">{f.question}</TableCell>
                    <TableCell className="text-right space-x-2">
                      <Button variant="outline" size="sm" onClick={() => handleEditFaq(f)}>
                        Editar
                      </Button>
                      <Button variant="destructive" size="sm" onClick={() => setDeleteFaqId(f.id)}>
                        Excluir
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
                {faqs.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={2} className="text-center">
                      Nenhum FAQ cadastrado.
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </Card>
        </TabsContent>

        <TabsContent value="entries" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>
                {editingEntryId ? 'Editar Regra' : 'Adicionar Regra / Contexto Privado'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleSaveEntry} className="flex flex-col gap-4">
                <Input
                  placeholder="Título do Assunto"
                  value={entryT}
                  onChange={(e) => setEntryT(e.target.value)}
                  required
                />
                <Textarea
                  placeholder="Conteúdo descritivo que a IA deve consultar..."
                  value={entryC}
                  onChange={(e) => setEntryC(e.target.value)}
                  rows={4}
                  required
                />
                <div className="flex justify-end gap-2">
                  {editingEntryId && (
                    <Button
                      type="button"
                      variant="outline"
                      onClick={() => {
                        setEditingEntryId(null)
                        setEntryT('')
                        setEntryC('')
                      }}
                    >
                      Cancelar
                    </Button>
                  )}
                  <Button type="submit">Salvar Alterações</Button>
                </div>
              </form>
            </CardContent>
          </Card>
          <Card>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Título da Regra</TableHead>
                  <TableHead className="w-40 text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {entries.map((e) => (
                  <TableRow key={e.id}>
                    <TableCell className="font-medium">{e.title}</TableCell>
                    <TableCell className="text-right space-x-2">
                      <Button variant="outline" size="sm" onClick={() => handleEditEntry(e)}>
                        Editar
                      </Button>
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={() => setDeleteEntryId(e.id)}
                      >
                        Excluir
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
                {entries.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={2} className="text-center">
                      Nenhuma regra cadastrada.
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </Card>
        </TabsContent>
      </Tabs>

      <AlertDialog open={!!deleteFaqId} onOpenChange={(open) => !open && setDeleteFaqId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Excluir Pergunta Frequente?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta ação não pode ser desfeita. Tem certeza de que deseja remover este FAQ da base de
              conhecimento da loja?
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={confirmDeleteFaq}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Sim, Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <AlertDialog open={!!deleteEntryId} onOpenChange={(open) => !open && setDeleteEntryId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Excluir Regra Base?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta ação não pode ser desfeita. Isso removerá as orientações dadas à inteligência
              artificial sobre esse tópico.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={confirmDeleteEntry}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Sim, Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}
